using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Gradio.Net.Components;
using Gradio.Net.Utils;
namespace Gradio.Net.Core.Flagging; /// <summary> /// The classic implementation of the FlaggingCallback abstract class in gradio<5.0. /// Each flagged sample (both the input and output data) is logged to a CSV file with headers. /// </summary> public class ClassicCSVLogger : FlaggingCallback { /// <summary> /// Gets or sets a value indicating whether to simplify file data before writing to CSV. /// </summary> public bool SimplifyFileData { get; set; } = true; /// <summary> /// Gets or sets the components that will provide flagged data. /// </summary> protected IEnumerable<Components.Component> Components { get; set; } = Enumerable.Empty<Components.Component>(); /// <summary> /// Gets or sets the directory where flagged data will be stored. /// </summary> protected string FlaggingDir { get; set; } = string.Empty; /// <summary> /// Initializes a new instance of the <see cref="ClassicCSVLogger"/> class. /// </summary> /// <param name="simplifyFileData">If true, file data will be simplified before writing to CSV.</param> public ClassicCSVLogger(bool simplifyFileData = true) { SimplifyFileData = simplifyFileData; } /// <summary> /// Sets up the logger with the specified components and flagging directory. /// </summary> /// <param name="components">The components that will provide flagged data.</param> /// <param name="flaggingDir">The directory where flagged data will be stored.</param> public override void Setup(IEnumerable<Components.Component> components, string flaggingDir) { Components = components; FlaggingDir = flaggingDir; Directory.CreateDirectory(flaggingDir); } /// <summary> /// Flags the specified data and returns the total number of flagged samples. /// </summary> /// <param name="flagData">The data to be flagged.</param> /// <param name="flagOption">The flag option that is being used.</param> /// <param name="username">The username of the user that is flagging the data, if logged in.</param> /// <returns>The total number of samples that have been flagged.</returns> public override int Flag(List<object> flagData, string? flagOption = null, string? username = null) { var flaggingDir = FlaggingDir; var logFilePath = Path.Combine(flaggingDir, "log.csv"); var isNew = !File.Exists(logFilePath); var componentList = Components.ToList(); var headers = componentList.Select((component, idx) => component.Label ?? $"component {idx}").ToList(); headers.AddRange(new[] { "flag", "username", "timestamp" }); var csvData = new List<string>(); for (int idx = 0; idx < componentList.Count; idx++) { var component = componentList[idx]; var sample = flagData[idx]; var saveDir = Path.Combine(flaggingDir, Utils.StripInvalidFilenameCharacters(component.Label ?? $"component {idx}")); Directory.CreateDirectory(saveDir); string data; if (Utils.IsPropUpdate(sample)) { data = sample.ToString() ?? string.Empty; } else { data = sample != null ? component.Flag(sample, saveDir) : string.Empty; if (SimplifyFileData) { data = Utils.SimplifyFileDataInString(data); } } csvData.Add(data); } csvData.Add(flagOption ?? string.Empty); csvData.Add(username ?? string.Empty); csvData.Add(DateTime.Now.ToString()); using (var writer = new StreamWriter(logFilePath, true, System.Text.Encoding.UTF8)) { if (isNew) { writer.WriteLine(string.Join(",", headers.Select(h => $"\"{h}\""))); } writer.WriteLine(string.Join(",", csvData.Select(d => $"\"{d}\""))); } using (var reader = new StreamReader(logFilePath, System.Text.Encoding.UTF8)) { var lineCount = 0; while (reader.ReadLine() != null) { lineCount++; } return lineCount - 1; } } } 
